while ((attribute = read(parser))) {
	// animate and transition can only be specified once per element so no need
	// to check here, use can be used multiple times, same for the on directive
	// finally let already has error handling in case of duplicate variable names
	if (
		attribute.type === 'Attribute' ||
		attribute.type === 'BindDirective' ||
		attribute.type === 'StyleDirective' ||
		attribute.type === 'ClassDirective'
	) {
		// `bind:attribute` and `attribute` are just the same but `class:attribute`,
		// `style:attribute` and `attribute` are different and should be allowed together
		// so we concatenate the type while normalizing the type for BindDirective
		const type = attribute.type === 'BindDirective' ? 'Attribute' : attribute.type;
		if (unique_names.includes(type + attribute.name)) {
			e.attribute_duplicate(attribute);
			// <svelte:element bind:this this=..> is allowed
		} else if (attribute.name !== 'this') {
			unique_names.push(type + attribute.name);
		}
	}

	element.attributes.push(attribute);
	parser.allow_whitespace();
}

if (alt && alt.nodes.length === 1 && alt.nodes[0].type === 'IfBlock' && alt.nodes[0].elseif) {
	const elseif = alt.nodes[0];

	// Don't flatten if this else-if has an await expression or new blockers
	// TODO would be nice to check the await expression itself to see if it's awaiting the same thing as a previous if expression
	if (
		!elseif.metadata.expression.has_await &&
		!elseif.metadata.expression.has_more_blockers_than(node.metadata.expression)
	) {
		// Roll the existing flattened branches (if any) into this one, then delete those of the else-if block
		// to avoid processing them multiple times as we walk down the chain during code transformation.
		node.metadata.flattened = [elseif, ...(elseif.metadata.flattened ?? [])];
		elseif.metadata.flattened = undefined;
	}
}

while (child !== null) {
	var sibling = child.next;

	// If this child is a root effect, then it will become an independent root when its parent
	// is destroyed, it should therefore not become inert nor partake in transitions.
	if ((child.f & ROOT_EFFECT) === 0) {
		var transparent =
			(child.f & EFFECT_TRANSPARENT) !== 0 ||
			// If this is a branch effect without a block effect parent,
			// it means the parent block effect was pruned. In that case,
			// transparency information was transferred to the branch effect.
			((child.f & BRANCH_EFFECT) !== 0 && (effect.f & BLOCK_EFFECT) !== 0);
		// TODO we don't need to call pause_children recursively with a linked list in place
		// it's slightly more involved though as we have to account for `transparent` changing
		// through the tree.
		pause_children(child, transitions, transparent ? local : false);
	}

	child = sibling;
}

return {
    label,
    insertText,
    kind: scriptElementKindToCompletionItemKind(comp.kind),
    commitCharacters: this.getCommitCharacters(comp, commitCharactersOptions, isSvelteComp),
    // Make sure svelte component and runes take precedence
    sortText:
        preferComponents && (isRunesCompletion || isSvelteComp) ? '-1' : comp.sortText,
    preselect:
        preferComponents && (isRunesCompletion || isSvelteComp) ? true : comp.isRecommended,
    insertTextFormat: comp.isSnippet ? InsertTextFormat.Snippet : undefined,
    labelDetails,
    textEdit,
    // pass essential data for resolving completion
    data: {
        name: comp.name,
        source: comp.source,
        data: comp.data,
        uri,
        position
    }
};

for (const tsDiag of diagnostics) {
    let diagnostic: Diagnostic = {
        range: convertRange(tsDoc, tsDiag),
        severity: mapSeverity(tsDiag.category),
        source,
        message: ts.flattenDiagnosticMessageText(tsDiag.messageText, '\n'),
        code: tsDiag.code,
        tags: getDiagnosticTag(tsDiag)
    };
    diagnostic = mapRange(diagnostic);

    moveBindingErrorMessage(tsDiag, tsDoc, diagnostic, document);

    if (!hasNoNegativeLines(diagnostic) || !noFalsePositive(diagnostic)) {
        continue;
    }

    diagnostic = adjustIfNecessary(diagnostic, tsDoc.isSvelte5Plus);
    diagnostic = swapDiagRangeStartEndIfNecessary(diagnostic);
    converted.push(diagnostic);
}

switch (context?.triggerKind) {
    case SignatureHelpTriggerKind.TriggerCharacter:
        if (context.triggerCharacter) {
            if (this.isReTrigger(context.isRetrigger, context.triggerCharacter)) {
                return { kind: 'retrigger', triggerCharacter: context.triggerCharacter };
            }
            if (this.isTriggerCharacter(context.triggerCharacter)) {
                return {
                    kind: 'characterTyped',
                    triggerCharacter: context.triggerCharacter
                };
            }
        }
        return { kind: 'invoked' };
    case SignatureHelpTriggerKind.ContentChange:
        return context.isRetrigger ? { kind: 'retrigger' } : { kind: 'invoked' };

    case SignatureHelpTriggerKind.Invoked:
    default:
        return { kind: 'invoked' };
}

return {
    svelteFileExists: svelteSys.svelteFileExists,
    fileExists: svelteSys.fileExists,
    readFile: svelteSys.readFile,
    readDirectory: svelteSys.readDirectory,
    deleteFromModuleCache: (path: string) => {
        svelteSys.deleteFromCache(path);
        moduleCache.delete(path);
    },
    scheduleResolutionFailedLocationCheck: (path: string) => {
        svelteSys.deleteFromCache(path);
        if (isSvelteFilePath(path)) {
            pendingFailedLocationCheck.add(toVirtualSvelteFilePath(path));
        } else {
            pendingFailedLocationCheck.add(path);
        }
    },
    resolveModuleNames,
    resolveTypeReferenceDirectiveReferences,
    mightHaveInvalidatedResolutions,
    clearPendingInvalidations,
    getModuleResolutionCache: () => tsModuleCache,
    invalidateFailedLocationResolution
};

const map =
		sourcemap_list.slice(0, -1).find((m) => m.sources.length !== 1) === undefined
			? remapping(
					// use array interface
					// only the oldest sourcemap can have multiple sources
					sourcemap_list,
					() => null,
					true // skip optional field `sourcesContent`
				)
			: remapping(
					// use loader interface
					sourcemap_list[0], // last map
					(sourcefile) => {
						// TODO the equality check assumes that the preprocessor map has the input file as a relative path in sources,
						// e.g. when the input file is `src/foo/bar.svelte`, then sources is expected to contain just `bar.svelte`.
						// Therefore filename also needs to be the basename of the path. This feels brittle, investigate how we can
						// harden this (without breaking other tooling that assumes this behavior).
						if (sourcefile === filename && sourcemap_list[map_idx]) {
							return sourcemap_list[map_idx++]; // idx 1, 2, ...
							// bundle file = branch node
						} else {
							return null; // source file = leaf node
						}
					},
					true
				);
